import type { CampaignPlayer, UserCampaignType } from '../types/userCampaign';

/**
 * Ready-made campaign scenarios (templates). Not part of the campaign
 * registry — the DM instantiates one via the wizard / World Home, producing a
 * fresh isolated campaign whose Locations/NPC/Enemies/Factions cards are
 * pre-filled from canon documents, with images and relations. Editable and
 * deletable like any user campaign.
 *
 * Relations are wired by `key`: an NPC's `locationKey` and an enemy's
 * `locationKeys` reference a location's `key`; the seed resolves them to real
 * ids so the cards cross-link (location → its NPCs/enemies, NPC → its location,
 * enemy → its locations).
 */
const ART = '/scenarios/caldran-captivity';

export interface ScenarioLocation { key: string; title: string; type?: string; description?: string; dmNotes?: string; image?: string; x?: number; y?: number }
export interface ScenarioNpc { name: string; role?: string; description?: string; dmNotes?: string; image?: string; locationKey?: string }
export interface ScenarioEnemy { title: string; ac?: number; hp?: number; description?: string; dmNotes?: string; image?: string; locationKeys?: string[] }
export interface ScenarioFaction { name: string; role?: string; description?: string; image?: string }
export interface ScenarioQuest { title: string; description?: string; dmNotes?: string; locationKey?: string; status?: string; image?: string; legacyTitles?: string[] }
export interface ScenarioImage { title: string; src: string; playerSafe?: boolean }
export interface ScenarioBattleMapLink { battleMapId: string; locationKey: string }
export type ScenarioPlayer = Omit<CampaignPlayer, 'id'>;

export interface CampaignScenario {
  id: string;
  title: string;
  type: UserCampaignType;
  baseMapId: string;
  regionIds: string[];
  summary: string;
  battleMapIds?: string[];
  battleMapLinks?: ScenarioBattleMapLink[];
  locations: ScenarioLocation[];
  npcs: ScenarioNpc[];
  enemies: ScenarioEnemy[];
  factions: ScenarioFaction[];
  quests: ScenarioQuest[];
  players?: ScenarioPlayer[];
  images?: ScenarioImage[];
}

