export const CAMPAIGN_SCENARIOS: CampaignScenario[] = [CALDRAN_CAPTIVITY];

export function getScenarioById(id: string): CampaignScenario | undefined {
  return CAMPAIGN_SCENARIOS.find((s) => s.id === id);
}
